module barrel_shifter(
    input [7:0] data_in,
    input [2:0] shift_amt,
    input direction,
    output reg [7:0] data_out
);
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    always @(*) begin
        if (direction == 1'b0) begin // Left shift
            data_out = data_in << shift_amt;
        end else begin // Right shift
            data_out = data_in >> shift_amt;
        end
    end
endmodule
